#!/usr/bin/env python3\n\"\"\"\nTest S1/S2 Decision Tracking with Existing Flee System\n\nThis script tests our S1/S2 tracking system with Flee's existing cognitive implementation\nto validate that we can detect and measure S1 vs S2 behavioral differences.\n\"\"\"\n\nimport sys\nfrom pathlib import Path\n\n# Add current directory to path\ncurrent_dir = Path(__file__).parent\nif str(current_dir) not in sys.path:\n    sys.path.insert(0, str(current_dir))\n\ndef test_s1s2_tracking_integration():\n    \"\"\"Test S1/S2 tracking integration with existing Flee system\"\"\"\n    print(\"🧠 TESTING S1/S2 TRACKING INTEGRATION\")\n    print(\"=\" * 50)\n    \n    try:\n        # Import Flee components\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location, Ecosystem\n        from flee import moving\n        from s1s2_decision_tracker import S1S2DecisionTracker\n        \n        print(\"✅ Imports successful\")\n        \n        # Initialize Flee settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        SimulationSettings.move_rules[\"conflict_threshold\"] = 0.5\n        print(\"✅ Flee settings initialized\")\n        \n        # Create simple test scenario\n        ecosystem = Ecosystem()\n        \n        # Create locations\n        origin = Location(\"Origin\", 0, 0, 1000)\n        origin.conflict = 0.8  # High conflict to potentially trigger S2\n        origin.time_of_conflict = 0\n        \n        camp = Location(\"Camp\", 100, 0, 5000)\n        camp.camp = True\n        \n        ecosystem.addLocation(origin)\n        ecosystem.addLocation(camp)\n        ecosystem.linkUp(\"Origin\", \"Camp\", 100.0)\n        \n        print(\"✅ Test scenario created (Origin with conflict → Camp)\")\n        \n        # Create S1/S2 tracker\n        tracker = S1S2DecisionTracker()\n        \n        # Create test agents with different connectivity levels\n        test_agents = []\n        for i in range(10):\n            connections = i  # 0-9 connections to test S1/S2 threshold\n            agent = Person(origin, attributes={\"connections\": connections})\n            agent._s1s2_tracker = tracker  # Attach tracker to agent\n            test_agents.append(agent)\n            ecosystem.addAgent(origin, attributes={\"connections\": connections})\n        \n        print(f\"✅ Created {len(test_agents)} test agents with connections 0-9\")\n        \n        # Test S1/S2 decision making\n        print(\"\\n🔍 TESTING S1/S2 DECISION PATTERNS\")\n        print(\"-\" * 40)\n        \n        s1_count = 0\n        s2_count = 0\n        \n        for time in [1, 15]:  # Test during conflict and recovery period\n            print(f\"\\nTime {time}:\")\n            \n            for i, agent in enumerate(test_agents):\n                # Test calculateMoveChance (this is where S1/S2 switching happens)\n                movechance, system2_active = moving.calculateMoveChance(agent, False, time)\n                \n                # Manual tracking for testing (normally integrated into calculateMoveChance)\n                decision_factors = {\n                    'conflict_level': agent.location.conflict,\n                    'connections': agent.attributes.get('connections', 0),\n                    'time': time,\n                    'recovery_period': time >= 10\n                }\n                \n                # Simulate route selection\n                route = []\n                if movechance > 0.5:  # Agent likely to move\n                    route = moving.selectRoute(agent, time, system2_active=system2_active)\n                \n                # Track the decision\n                tracker.track_decision(agent, system2_active, movechance, route, time, decision_factors)\n                \n                if system2_active:\n                    s2_count += 1\n                else:\n                    s1_count += 1\n                \n                print(f\"   Agent {i} (conn={agent.attributes['connections']}): \"\n                      f\"S{'2' if system2_active else '1'}, movechance={movechance:.3f}\")\n        \n        print(f\"\\n📊 DECISION SUMMARY:\")\n        print(f\"   S1 decisions: {s1_count}\")\n        print(f\"   S2 decisions: {s2_count}\")\n        print(f\"   S2 activation rate: {s2_count/(s1_count+s2_count):.1%}\")\n        \n        # Analyze results\n        print(\"\\n📈 ANALYZING S1/S2 BEHAVIORAL DIFFERENCES\")\n        print(\"-\" * 40)\n        \n        analysis = tracker.analyze_behavioral_differences()\n        tracker.print_summary()\n        \n        # Save results\n        tracker.save_decision_log(\"test_s1s2_decisions.csv\")\n        tracker.save_analysis_results(\"test_s1s2_analysis.json\")\n        \n        print(\"\\n✅ S1/S2 tracking test completed successfully!\")\n        \n        # Validate key expectations\n        s2_activation_rate = analysis['system2_activation']['s2_activation_rate']\n        \n        if s2_activation_rate > 0:\n            print(f\"✅ S2 activation detected ({s2_activation_rate:.1%})\")\n        else:\n            print(\"⚠️  No S2 activation detected - check conditions\")\n        \n        if s1_count > 0 and s2_count > 0:\n            print(\"✅ Both S1 and S2 decisions recorded\")\n        else:\n            print(\"⚠️  Only one cognitive mode detected\")\n        \n        return True\n        \n    except Exception as e:\n        print(f\"❌ S1/S2 tracking test failed: {e}\")\n        import traceback\n        traceback.print_exc()\n        return False\n\ndef test_s2_lazy_activation():\n    \"\"\"Test that S2 is lazy - only activates under specific conditions\"\"\"\n    print(\"\\n🦥 TESTING S2 LAZY ACTIVATION (KAHNEMAN)\")\n    print(\"=\" * 50)\n    \n    try:\n        from flee.SimulationSettings import SimulationSettings\n        from flee.flee import Person, Location\n        from flee import moving\n        \n        # Initialize settings\n        SimulationSettings.ReadFromYML(\"test_data/test_settings.yml\")\n        SimulationSettings.move_rules[\"TwoSystemDecisionMaking\"] = True\n        \n        # Test conditions for S2 activation\n        test_conditions = [\n            {\"name\": \"Low conflict\", \"conflict\": 0.3, \"connections\": 5, \"time\": 15, \"expected_s2\": False},\n            {\"name\": \"High conflict, low connections\", \"conflict\": 0.8, \"connections\": 1, \"time\": 15, \"expected_s2\": False},\n            {\"name\": \"High conflict, early time\", \"conflict\": 0.8, \"connections\": 5, \"time\": 5, \"expected_s2\": False},\n            {\"name\": \"All conditions met\", \"conflict\": 0.8, \"connections\": 5, \"time\": 15, \"expected_s2\": True},\n        ]\n        \n        print(f\"{'Condition':<25} {'Conflict':<8} {'Conn':<4} {'Time':<4} {'Expected':<8} {'Actual':<6} {'✓'}\")\n        print(\"-\" * 70)\n        \n        all_correct = True\n        \n        for condition in test_conditions:\n            # Create test location and agent\n            location = Location(\"TestLoc\", 0, 0, 1000)\n            location.conflict = condition[\"conflict\"]\n            location.time_of_conflict = 0\n            \n            agent = Person(location, attributes={\"connections\": condition[\"connections\"]})\n            \n            # Test S2 activation\n            movechance, system2_active = moving.calculateMoveChance(agent, False, condition[\"time\"])\n            \n            expected = condition[\"expected_s2\"]\n            correct = system2_active == expected\n            all_correct = all_correct and correct\n            \n            status = \"✅\" if correct else \"❌\"\n            \n            print(f\"{condition['name']:<25} {condition['conflict']:<8.1f} {condition['connections']:<4} \"\n                  f\"{condition['time']:<4} {'S2' if expected else 'S1':<8} {'S2' if system2_active else 'S1':<6} {status}\")\n        \n        if all_correct:\n            print(\"\\n✅ S2 lazy activation working correctly!\")\n            print(\"   S2 only activates when: conflict > 0.6 AND recovery period AND connections > 3\")\n        else:\n            print(\"\\n❌ S2 activation not working as expected\")\n        \n        return all_correct\n        \n    except Exception as e:\n        print(f\"❌ S2 lazy activation test failed: {e}\")\n        return False\n\ndef main():\n    \"\"\"Run all S1/S2 tracking tests\"\"\"\n    print(\"🧠 S1/S2 DECISION TRACKING VALIDATION\")\n    print(\"=\" * 60)\n    print(\"Testing integration with existing Flee cognitive system\")\n    print(\"Focus: Kahneman's 'S2 is lazy' principle\")\n    print(\"=\" * 60)\n    \n    tests = [\n        (\"S1/S2 Tracking Integration\", test_s1s2_tracking_integration),\n        (\"S2 Lazy Activation\", test_s2_lazy_activation)\n    ]\n    \n    results = {}\n    \n    for test_name, test_func in tests:\n        try:\n            results[test_name] = test_func()\n        except Exception as e:\n            print(f\"❌ {test_name} crashed: {e}\")\n            results[test_name] = False\n    \n    # Summary\n    print(\"\\n\" + \"=\" * 60)\n    print(\"TEST SUMMARY\")\n    print(\"=\" * 60)\n    \n    passed = 0\n    total = len(tests)\n    \n    for test_name, result in results.items():\n        status = \"✅ PASS\" if result else \"❌ FAIL\"\n        print(f\"{test_name:<30} {status}\")\n        if result:\n            passed += 1\n    \n    print(f\"\\nOverall: {passed}/{total} tests passed\")\n    \n    if passed == total:\n        print(\"\\n🎉 All S1/S2 tracking tests passed!\")\n        print(\"\\n📋 Key Validations:\")\n        print(\"   ✅ S1/S2 tracking system integrates with existing Flee\")\n        print(\"   ✅ S2 lazy activation works correctly (Kahneman principle)\")\n        print(\"   ✅ Behavioral differences between S1 and S2 are detectable\")\n        print(\"\\n🚀 Ready to implement refugee-specific scenarios!\")\n        return True\n    else:\n        print(\"\\n⚠️  Some tests failed. Check S1/S2 integration.\")\n        return False\n\nif __name__ == \"__main__\":\n    success = main()\n    sys.exit(0 if success else 1)\n"